  # Builds WHERE clauses with parameterized placeholders
  defp build_safe_where_clauses(filters) do
    # Only allow filtering on known columns (whitelist)
    allowed_filters = %{
      "role" => :equality,
      "email" => :like,
      "name" => :like,
      "active" => :boolean,
      "inserted_after" => :date_gte,
      "inserted_before" => :date_lte
    }

    filters
    |> Enum.filter(fn {key, value} ->
      Map.has_key?(allowed_filters, key) && value != nil && value != ""
    end)
    |> Enum.reduce({[], []}, fn {key, value}, {clauses, params} ->
      param_index = length(params) + 1
      filter_type = Map.get(allowed_filters, key)

      db_column = column_mapping(key)

      case filter_type do
        :equality ->
          {clauses ++ ["#{db_column} = $#{param_index}"], params ++ [value]}

        :like ->
          {clauses ++ ["#{db_column} ILIKE $#{param_index}"], params ++ ["%#{sanitize_like(value)}%"]}

        :boolean ->
          {clauses ++ ["#{db_column} = $#{param_index}"], params ++ [to_boolean(value)]}

        :date_gte ->
