defmodule MyApp.Admin.UserQuery do
  @moduledoc """
  Preferred approach: Use Ecto's query DSL which handles parameterization
  automatically. This is safer, more readable, and more maintainable.
  """

  import Ecto.Query
  alias MyApp.Repo
  alias MyApp.Accounts.User

  def filter_users(filters) do
    User
    |> apply_filters(filters)
    |> order_by([u], desc: u.inserted_at)
    |> limit(100)
    |> Repo.all()
  end

  defp apply_filters(query, filters) do
    Enum.reduce(filters, query, fn
      {"role", role}, query when is_binary(role) and role != "" ->
        where(query, [u], u.role == ^role)

      {"name", name}, query when is_binary(name) and name != "" ->
        where(query, [u], ilike(u.name, ^"%#{sanitize_like(name)}%"))

      {"email", email}, query when is_binary(email) and email != "" ->
        where(query, [u], ilike(u.email, ^"%#{sanitize_like(email)}%"))

      {"active", active}, query ->
        where(query, [u], u.active == ^to_boolean(active))

      _other, query ->
        query
    end)
  end

  defp sanitize_like(term) do
    term
    |> String.replace("\\", "\\\\")
    |> String.replace("%", "\\%")
    |> String.replace("_", "\\_")
  end

  defp to_boolean("true"), do: true
  defp to_boolean("1"), do: true
  defp to_boolean(true), do: true
  defp to_boolean(_), do: false
end


